+   */
+  function describeVideoError(err) {
+    if (!err) return '未知错误';
+    switch (err.code) {
+      case 1: return '加载被中止';
+      case 2: return '网络错误(URL 不通 / CORS 拦截 / Mixed Content)';
+      case 3: return '视频解码失败(格式不支持或文件损坏)';
+      case 4: return '视频源不支持(浏览器无法播放该格式, HLS 可能需要 Safari 或 hls.js)';
